INSERT INTO prescription_examples (student_key, student_profile, workouts, workout_split) VALUES ('suellen_tremarin', '{"name":"Suelen Tremarin","mapped_name":null,"birth_date":"1983-04-02","profession":"Consultora financeira","sports_history":"Pratiquei Crossfit por 4 anos, não era a mais aplicada, mas ia bem. 2 anos de funcional indo 3 a 4 vezes na semana, 2 vezes por semana de yoga. Nunca fui pra uma academia convencional.","injuries":["O ombro esquerdo incomoda na hora de fazer snatch (não sinto falta) algumas dores na cervical por causa de protusão","e ultimamente dores na lombar."],"health_conditions":["Acho que tá boa."],"medications":["Não."],"current_practice":"2 anos de funcional + 6 meses de pilates + 2 meses de yoga","goal":"Estética e saúde n?! Envelhecer bem!","weekly_frequency":2,"session_duration":null,"gender":"F","experience_level":"iniciante","form_timestamp":"2023/06/15 12:47:58 PM GMT-3"}'::jsonb, '{"A":{"focus":"","exercises":[{"name":"Agachamento Búlgaro Halteres","method":"Tradicional","series_data":{"rep":"2025-08-08 00:00:00","peso":"18-20kg cada halter","intervalo":"1'' - 1''30\""}},{"name":"Remada Serrote Vertical","method":"Tradicional","series_data":{"rep":"2025-08-08 00:00:00","peso":"14-16kg cada halter","intervalo":"1''30\""}},{"name":"Leg 45°","method":"Tradicional","series_data":{"rep":"10-14","intervalo":"1''30\"","obs":"(pés ligeiramente para baixo na plataforma)"}},{"name":"Puxada Frente Pronada Aberta","method":"Tradicional","series_data":{"rep":"2025-08-06 00:00:00","peso":"Máx","intervalo":"1''30\"","obs":"Fazer a pegada com a palma das mãos para frente e um pouco mais afastada que a largura dos seus ombros"}},{"name":"Cadeira Extensora + Rosca Direta Halteres","method":"BiSet","series_data":{"rep":"12+12","peso":"Máx na Extensora e aprox. 7-9kg halteres","intervalo":"1''30\""}},{"name":"Facepull + Crucifixo Inverso Halteres","method":"BiSet","series_data":{"rep":"12+12","peso":"Aprox 4 blocos Facepull e  5-8kg no Crucifixo","intervalo":"1''30\"","obs":"Facepull polia na altura do seu rosto e crucifixo halteres livre, manter a pegada em neutro (palma das mãos uma de frente para a outra) no crucifixo"}}]},"B":{"focus":"","exercises":[{"name":"Deadlift Barra","method":"Tradicional","series_data":{"rep":"2025-08-06 00:00:00","peso":"Máx","intervalo":"2''"}},{"name":"Elevação Frontal + Desenvolvimento de Ombros Barra","method":"BiSet","series_data":{"rep":"10+10","peso":"Aprox 6-8kg na Elevação e 20-24 no desenvolvimento","intervalo":"1''30\""}},{"name":"Cadeira Flexora Tronco inclinado à frente","method":"Tradicional","series_data":{"rep":"10-14","peso":"Máx","intervalo":"1''30\"","obs":"Deixar a coluna bem retinha durante toda a execução. Inclinar o tronco à frente vai colocar os posteriores de coxa em uma posição de alongamento maior, dificultando um pouco mais o exercício."}},{"name":"Elevação Lateral Unilateral Polia Baixa","method":"Tradicional","series_data":{"rep":"12 - 12","intervalo":"1''30\"","obs":"Deixar o cabo passar por trás do seu corpo e realizar a elevação lateral usando a manopla."}},{"name":"Mesa Flexora + Abdominal Curto","method":"BiSet","series_data":{"rep":"15 + 20","intervalo":"1''30\""}},{"name":"Flexão de Braços + Russian Twists com KB","method":"BiSet","series_data":{"rep":"6-8 + 30","intervalo":"1''30\"","obs":"Na flexão, deixar os cotovelos a mais ou menos 45° em relação ao tronco. Nos russian twists, contar de forma unilateral, segurando 1 KB com as 2 mãos"}}]},"C":{"focus":"","exercises":[{"name":"Mesa Flexora","method":"Tradicional","series_data":{"rep":"2025-12-10 00:00:00","peso":"35.0","intervalo":"1''30\"","obs":"Segurar 2\" a cada repetição quando os joelhos chegarem a 90°"}},{"name":"Cadeira Flexora","method":"Tradicional","series_data":{"rep":"2025-12-10 00:00:00","peso":"45.0","intervalo":"1''30\""}},{"name":"Hip Thrust","method":"Pico de Contração","series_data":{"rep":"2025-12-10 00:00:00","peso":"32.0","intervalo":"1''30\"","obs":"Quando realizar a amplitude máxima da abdução do quadril, segurar a contração por 2\" a cada repetição"}},{"name":"Abdução de Quadril + Extensão de Quadril Polia Baixa","method":"Pico de Contração","series_data":{"rep":"2025-10-08 00:00:00","peso":"30.0","intervalo":"1''30\" - 2''","obs":"Quando realizar a amplitude máxima da extensão do quadril, segurar a contração por 2\" a cada repetição"}},{"name":"Panturrilha Máquina em Pé","method":"Tradicional","series_data":{"rep":"12+12","peso":"20.0","intervalo":"1''","obs":"X"}}]},"D":{"focus":"","exercises":[{"name":"Crucifixo Máquina + Elevação Frontal","method":"Bi-Set","series_data":{"rep":"6+12","peso":"25.0","intervalo":"1''30\""}},{"name":"Desenvolvimento de Ombros Halteres","method":"Tradicional","series_data":{"rep":"2025-10-10 00:00:00","peso":"15+7.5","intervalo":"1''"}},{"name":"Elevação Lateral Crossover","method":"Tradicional","series_data":{"rep":"10-15","peso":"43.0","intervalo":"1''30\""}},{"name":"Tríceps Barra Crossover","method":"Tradicional","series_data":{"rep":"10-15","peso":"6.0","intervalo":"1''30\""}},{"name":"Recuo no Smith","method":"Tradicional","series_data":{"rep":"10-15","peso":"10.0","intervalo":"1''30\""}},{"name":"3 Séries: 10 Abdominais V + 15 Abdominais Curtos + 30\"/30\" Prancha Lateral","method":"Tradicional","series_data":{"rep":"10-15","peso":"10kg","intervalo":"1''30\""}}]},"E":{"focus":"","exercises":[{"name":"Sumo Deadlift nos Caixotes","method":"Tradicional","series_data":{"rep":"12-16","peso":"50kg","intervalo":"1''30"}},{"name":"Cadeira Abdutora","method":"Tradicional","series_data":{"rep":"10-14","peso":"12kg"}},{"name":"Glúteo Coice Crossover","method":"Tradicional","series_data":{"rep":"12-16","peso":"KB 16kg","intervalo":"1''30\"","obs":"Se possível, usar um calço no calcanhar para realizar o movimento com o tronco bem ereto."}},{"name":"Leg 45°","method":"Tradicional","series_data":{"rep":"10-14","peso":"Aprox. 5kg","intervalo":"1''30\"","cadencia":"Deixar o banco inclinado a 45°, realizar o exercício da rosca direta com os braços atrás da linha do tronco (bíceps em condição de alongamento)."}},{"name":"25''-30'' Cardio Intenso (corrida, bike, remo ou caminhada inclinada) - 155-180bpm","method":"Tradicional","series_data":{"rep":"15-20","peso":"32.0","intervalo":"1''30\"","cadencia":"Quando estiver chegando próxima a falha, realizar de 3 a 5 repetições parciais a mais."}},{"name":"25''-30'' Cardio Intenso (corrida ou caminhada inclinada) - 155-180bpm","method":"Tradicional","series_data":{"rep":"15/15","peso":"4 blocos","intervalo":"1''"}}]}}'::jsonb, ARRAY['A','B','C','D','E']::TEXT[]) ON CONFLICT (student_key) DO UPDATE SET student_profile = EXCLUDED.student_profile, workouts = EXCLUDED.workouts, workout_split = EXCLUDED.workout_split;